import uuid

import boto3
from botocore.exceptions import ClientError
from fastapi import APIRouter, HTTPException, UploadFile, File, Form
from sqlalchemy.orm import Session

from app.api.deps import DBSession
from app.core.config import settings
from app.schemas.project import (
    ProjectCreate,
    ProjectDetailResponse,
    ProjectEntryResponse,
    ProjectResponse,
    ProjectUpdate,
)
from app.services import project_service

router = APIRouter(prefix="/projects")

s3_client = boto3.client("s3")
BUCKET = settings.s3_bucket_name


def _upload_audio_to_s3(file: UploadFile) -> tuple[str, str]:
    """Upload audio file to S3, return (url, key)."""
    ext = file.filename.rsplit(".", 1)[-1] if file.filename and "." in file.filename else "audio"
    key = f"audio/{uuid.uuid4().hex}.{ext}"
    s3_client.upload_fileobj(
        file.file,
        BUCKET,
        key,
        ExtraArgs={"ContentType": file.content_type or "audio/mpeg"},
    )
    url = f"https://{BUCKET}.s3.amazonaws.com/{key}"
    return url, key


@router.get("", response_model=list[ProjectResponse])
def list_projects(db: Session = DBSession):
    return project_service.get_all_projects(db)


@router.post("", response_model=ProjectResponse, status_code=201)
def create_project(data: ProjectCreate, db: Session = DBSession):
    return project_service.create_project(db, data)


@router.get("/{project_id}", response_model=ProjectDetailResponse)
def get_project(project_id: int, db: Session = DBSession):
    project = project_service.get_project_by_id(db, project_id)
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    entry_count = len(project.entries)
    return ProjectDetailResponse(
        id=project.id,
        name=project.name,
        description=project.description,
        created_at=project.created_at,
        updated_at=project.updated_at,
        entry_count=entry_count,
        entries=[
            ProjectEntryResponse(
                id=e.id,
                project_id=e.project_id,
                text_content=e.text_content,
                audio_url=e.audio_url,
                audio_filename=e.audio_filename,
                created_at=e.created_at,
            )
            for e in project.entries
        ],
    )


@router.put("/{project_id}", response_model=ProjectResponse)
def update_project(project_id: int, data: ProjectUpdate, db: Session = DBSession):
    project = project_service.update_project(db, project_id, data)
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    return project


@router.delete("/{project_id}", status_code=204)
def delete_project(project_id: int, db: Session = DBSession):
    ok = project_service.delete_project(db, project_id)
    if not ok:
        raise HTTPException(status_code=404, detail="Project not found")


@router.post("/{project_id}/entries", response_model=ProjectEntryResponse, status_code=201)
async def create_entry(
    project_id: int,
    text_content: str = Form(...),
    audio_file: UploadFile | None = File(None),
    db: Session = DBSession,
):
    audio_url = None
    audio_key = None
    audio_filename = None

    if audio_file and audio_file.filename:
        if not BUCKET:
            raise HTTPException(status_code=500, detail="S3_BUCKET_NAME not configured")
        try:
            audio_url, audio_key = _upload_audio_to_s3(audio_file)
            audio_filename = audio_file.filename
        except ClientError as e:
            raise HTTPException(status_code=500, detail=f"S3 upload failed: {str(e)}")

    entry = project_service.create_entry(
        db, project_id, text_content, audio_url, audio_key, audio_filename
    )
    if not entry:
        raise HTTPException(status_code=404, detail="Project not found")
    return entry


@router.delete("/{project_id}/entries/{entry_id}", status_code=204)
def delete_entry(project_id: int, entry_id: int, db: Session = DBSession):
    ok = project_service.delete_entry(db, entry_id)
    if not ok:
        raise HTTPException(status_code=404, detail="Entry not found")

