/* =========================================================
   AudioScript — Dark Editorial Theme
   Fonts: Playfair Display, Lora, DM Mono
   ========================================================= */

:root {
  --bg-base: #0d0d0f;
  --bg-surface: #131316;
  --bg-raised: #1a1a1f;
  --bg-hover: #202028;
  --bg-active: #252530;

  --border: rgba(255, 255, 255, 0.07);
  --border-focus: rgba(212, 175, 95, 0.5);

  --gold: #d4af5f;
  --gold-dim: rgba(212, 175, 95, 0.15);
  --gold-bright: #e8c87a;

  --text-primary: #f0ece0;
  --text-secondary: #9a9585;
  --text-muted: #5a5650;

  --red: #c0392b;
  --red-dim: rgba(192, 57, 43, 0.15);
  --green: #27ae60;

  --font-display: 'Playfair Display', Georgia, serif;
  --font-body: 'Lora', Georgia, serif;
  --font-mono: 'DM Mono', 'Courier New', monospace;

  --radius: 4px;
  --radius-lg: 8px;
  --sidebar-width: 280px;
  --header-height: 56px;

  --shadow: 0 4px 24px rgba(0, 0, 0, 0.4);
  --shadow-lg: 0 8px 48px rgba(0, 0, 0, 0.6);
}

/* ---- Reset ---- */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html { height: 100%; scroll-behavior: smooth; }

body {
  height: 100%;
  background: var(--bg-base);
  color: var(--text-primary);
  font-family: var(--font-body);
  font-size: 15px;
  line-height: 1.65;
  overflow: hidden;
}

/* ---- Background texture ---- */
.bg-texture {
  position: fixed;
  inset: 0;
  background-image:
    radial-gradient(ellipse at 20% 20%, rgba(212, 175, 95, 0.04) 0%, transparent 50%),
    radial-gradient(ellipse at 80% 80%, rgba(100, 80, 160, 0.04) 0%, transparent 50%);
  pointer-events: none;
  z-index: 0;
}

/* ---- Header ---- */
.site-header {
  position: fixed;
  top: 0; left: 0; right: 0;
  height: var(--header-height);
  background: rgba(13, 13, 15, 0.95);
  backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--border);
  z-index: 100;
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 100%;
  padding: 0 24px;
}

.logo {
  display: flex;
  align-items: center;
  gap: 10px;
}

.logo-icon {
  color: var(--gold);
  font-size: 18px;
  line-height: 1;
}

.logo-text {
  font-family: var(--font-display);
  font-size: 17px;
  font-weight: 700;
  letter-spacing: 0.04em;
  color: var(--text-primary);
}

.btn-new-project {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 8px 18px;
  background: var(--gold);
  color: #0d0d0f;
  border: none;
  border-radius: var(--radius);
  font-family: var(--font-mono);
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.06em;
  cursor: pointer;
  transition: background 0.2s, transform 0.1s;
}

.btn-new-project:hover { background: var(--gold-bright); transform: translateY(-1px); }
.btn-new-project:active { transform: translateY(0); }

.btn-new-project .btn-icon {
  font-size: 16px;
  line-height: 1;
}

/* ---- Layout ---- */
.app-layout {
  display: flex;
  height: 100vh;
  padding-top: var(--header-height);
  position: relative;
  z-index: 1;
}

/* ---- Sidebar ---- */
.sidebar {
  width: var(--sidebar-width);
  min-width: var(--sidebar-width);
  background: var(--bg-surface);
  border-right: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.sidebar-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 20px 20px 12px;
  border-bottom: 1px solid var(--border);
}

.sidebar-title {
  font-family: var(--font-mono);
  font-size: 10px;
  font-weight: 500;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--text-muted);
}

.project-count {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--gold);
  background: var(--gold-dim);
  padding: 2px 8px;
  border-radius: 20px;
}

.project-list {
  flex: 1;
  overflow-y: auto;
  padding: 8px 0;
}

.project-list::-webkit-scrollbar { width: 4px; }
.project-list::-webkit-scrollbar-track { background: transparent; }
.project-list::-webkit-scrollbar-thumb { background: var(--border); border-radius: 2px; }

.empty-sidebar {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 48px 20px;
  text-align: center;
  gap: 12px;
}

.empty-icon {
  font-size: 28px;
  color: var(--text-muted);
  opacity: 0.5;
}

.empty-sidebar p {
  font-size: 13px;
  color: var(--text-muted);
  font-family: var(--font-mono);
}

.btn-create-first {
  margin-top: 4px;
  padding: 8px 16px;
  background: transparent;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--text-secondary);
  font-family: var(--font-mono);
  font-size: 11px;
  letter-spacing: 0.06em;
  cursor: pointer;
  transition: border-color 0.2s, color 0.2s;
}

.btn-create-first:hover {
  border-color: var(--gold);
  color: var(--gold);
}

/* Project item in sidebar */
.project-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 20px;
  cursor: pointer;
  transition: background 0.15s;
  border-left: 2px solid transparent;
  gap: 12px;
}

.project-item:hover { background: var(--bg-hover); }

.project-item.active {
  background: var(--bg-active);
  border-left-color: var(--gold);
}

.project-item-info { flex: 1; min-width: 0; }

.project-item-name {
  font-family: var(--font-display);
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  margin-bottom: 2px;
}

.project-item.active .project-item-name { color: var(--gold); }

.project-item-meta {
  font-family: var(--font-mono);
  font-size: 10px;
  color: var(--text-muted);
}

.project-item-badge {
  font-family: var(--font-mono);
  font-size: 10px;
  color: var(--text-muted);
  background: var(--bg-raised);
  padding: 2px 7px;
  border-radius: 10px;
  flex-shrink: 0;
}

/* ---- Content Area ---- */
.content-area {
  flex: 1;
  overflow-y: auto;
  background: var(--bg-base);
}

.content-area::-webkit-scrollbar { width: 6px; }
.content-area::-webkit-scrollbar-track { background: transparent; }
.content-area::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }

/* Welcome screen */
.welcome-screen {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100%;
  min-height: calc(100vh - var(--header-height));
}

.welcome-inner {
  text-align: center;
  animation: fadeIn 0.6s ease;
}

.welcome-ornament {
  font-size: 48px;
  color: var(--gold);
  opacity: 0.3;
  margin-bottom: 24px;
  display: block;
}

.welcome-title {
  font-family: var(--font-display);
  font-size: 32px;
  font-weight: 400;
  font-style: italic;
  color: var(--text-secondary);
  margin-bottom: 12px;
}

.welcome-sub {
  font-size: 14px;
  color: var(--text-muted);
  line-height: 1.8;
}

/* ---- Project View ---- */
.project-view {
  padding: 40px 48px;
  max-width: 820px;
  animation: fadeIn 0.3s ease;
}

.project-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 36px;
  padding-bottom: 28px;
  border-bottom: 1px solid var(--border);
}

.project-breadcrumb {
  font-family: var(--font-mono);
  font-size: 10px;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--gold);
  margin-bottom: 8px;
}

.project-title {
  font-family: var(--font-display);
  font-size: 36px;
  font-weight: 700;
  line-height: 1.2;
  color: var(--text-primary);
  margin-bottom: 8px;
}

.project-desc {
  font-size: 14px;
  color: var(--text-secondary);
  font-style: italic;
}

.project-actions {
  display: flex;
  gap: 8px;
  padding-top: 4px;
}

.btn-icon-action {
  width: 36px;
  height: 36px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--bg-raised);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--text-muted);
  cursor: pointer;
  transition: all 0.2s;
}

.btn-icon-action:hover { border-color: var(--gold); color: var(--gold); background: var(--gold-dim); }

.btn-delete-project:hover { border-color: var(--red) !important; color: var(--red) !important; background: var(--red-dim) !important; }

/* ---- Entry Form ---- */
.entry-form-wrapper {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 24px;
  margin-bottom: 36px;
}

.entry-form-header {
  margin-bottom: 20px;
}

.form-label-tag {
  font-family: var(--font-mono);
  font-size: 10px;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--gold);
  background: var(--gold-dim);
  padding: 4px 10px;
  border-radius: 20px;
}

.form-field {
  margin-bottom: 18px;
}

.field-label {
  display: block;
  font-family: var(--font-mono);
  font-size: 11px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--text-muted);
  margin-bottom: 8px;
}

.optional { color: var(--text-muted); font-style: italic; text-transform: none; }
.required { color: var(--gold); }

textarea, input[type="text"] {
  width: 100%;
  background: var(--bg-base);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--text-primary);
  font-family: var(--font-body);
  font-size: 14px;
  padding: 12px 14px;
  resize: vertical;
  transition: border-color 0.2s;
  outline: none;
}

textarea:focus, input[type="text"]:focus {
  border-color: var(--border-focus);
}

textarea::placeholder, input::placeholder { color: var(--text-muted); }

.field-error {
  display: block;
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--red);
  margin-top: 4px;
  min-height: 16px;
}

/* Audio drop zone */
.audio-drop-zone {
  border: 1px dashed var(--border);
  border-radius: var(--radius);
  padding: 24px;
  text-align: center;
  cursor: pointer;
  transition: border-color 0.2s, background 0.2s;
  position: relative;
}

.audio-drop-zone:hover, .audio-drop-zone.drag-over {
  border-color: var(--gold);
  background: var(--gold-dim);
}

.file-input-hidden {
  position: absolute;
  inset: 0;
  opacity: 0;
  cursor: pointer;
  width: 100%;
  height: 100%;
}

.drop-icon {
  font-size: 28px;
  color: var(--text-muted);
  margin-bottom: 8px;
  display: block;
}

.drop-text {
  font-size: 13px;
  color: var(--text-secondary);
  margin-bottom: 4px;
}

.drop-link { color: var(--gold); text-decoration: underline; }

.drop-hint {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-muted);
}

.file-selected {
  display: flex;
  align-items: center;
  gap: 10px;
  justify-content: center;
}

.file-icon { color: var(--gold); font-size: 18px; }

.file-name {
  font-family: var(--font-mono);
  font-size: 12px;
  color: var(--text-primary);
  max-width: 240px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.file-remove {
  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 18px;
  line-height: 1;
  padding: 0 4px;
  transition: color 0.15s;
}

.file-remove:hover { color: var(--red); }

/* Form actions */
.form-actions { display: flex; justify-content: flex-end; }

.btn-submit {
  padding: 10px 24px;
  background: var(--gold);
  color: #0d0d0f;
  border: none;
  border-radius: var(--radius);
  font-family: var(--font-mono);
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.06em;
  cursor: pointer;
  transition: background 0.2s, transform 0.1s;
}

.btn-submit:hover { background: var(--gold-bright); transform: translateY(-1px); }
.btn-submit:active { transform: translateY(0); }
.btn-submit:disabled { opacity: 0.5; cursor: not-allowed; transform: none; }

/* ---- Entries Section ---- */
.entries-section { }

.entries-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 20px;
}

.entries-title {
  font-family: var(--font-mono);
  font-size: 10px;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--text-muted);
}

.entries-count {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-muted);
}

.entries-list {
  display: flex;
  flex-direction: column;
  gap: 16px;
  padding-bottom: 60px;
}

/* Entry card */
.entry-card {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 20px 24px;
  transition: border-color 0.2s;
  animation: slideUp 0.3s ease;
}

.entry-card:hover { border-color: rgba(212, 175, 95, 0.2); }

.entry-card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 14px;
}

.entry-date {
  font-family: var(--font-mono);
  font-size: 10px;
  color: var(--text-muted);
  letter-spacing: 0.06em;
}

.entry-delete-btn {
  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  opacity: 0;
  transition: opacity 0.2s, color 0.2s;
  padding: 2px 6px;
  font-size: 12px;
}

.entry-card:hover .entry-delete-btn { opacity: 1; }
.entry-delete-btn:hover { color: var(--red); }

.entry-text {
  font-size: 14px;
  color: var(--text-primary);
  line-height: 1.75;
  margin-bottom: 0;
  white-space: pre-wrap;
  word-break: break-word;
}

.entry-audio-wrapper {
  margin-top: 16px;
  padding-top: 16px;
  border-top: 1px solid var(--border);
}

.entry-audio-label {
  font-family: var(--font-mono);
  font-size: 10px;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--gold);
  margin-bottom: 10px;
  display: flex;
  align-items: center;
  gap: 6px;
}

.entry-audio-label::before {
  content: '♪';
  font-size: 12px;
}

.entry-filename {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-muted);
  margin-bottom: 8px;
}

audio {
  width: 100%;
  height: 36px;
  border-radius: var(--radius);
  filter: sepia(0.5);
}

/* Empty entries */
.empty-entries {
  text-align: center;
  padding: 48px 20px;
}

.empty-entries-icon {
  font-size: 32px;
  color: var(--text-muted);
  opacity: 0.3;
  display: block;
  margin-bottom: 12px;
}

.empty-entries p {
  font-size: 13px;
  color: var(--text-muted);
  font-style: italic;
}

/* Spinner */
.spinner {
  width: 28px;
  height: 28px;
  border: 2px solid var(--border);
  border-top-color: var(--gold);
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
  margin: 40px auto;
}

.entries-loading {
  display: flex;
  justify-content: center;
}

/* ---- Modals ---- */
.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.75);
  backdrop-filter: blur(4px);
  z-index: 200;
  display: flex;
  align-items: center;
  justify-content: center;
  animation: fadeIn 0.2s ease;
}

.modal {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 32px;
  width: 480px;
  max-width: 90vw;
  box-shadow: var(--shadow-lg);
  animation: scaleIn 0.2s ease;
}

.modal-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 24px;
}

.modal-title {
  font-family: var(--font-display);
  font-size: 22px;
  font-weight: 700;
  color: var(--text-primary);
}

.modal-close {
  background: none;
  border: none;
  color: var(--text-muted);
  font-size: 22px;
  cursor: pointer;
  line-height: 1;
  transition: color 0.15s;
  padding: 2px;
}

.modal-close:hover { color: var(--text-primary); }

.modal-form .form-field { margin-bottom: 20px; }

.modal-actions {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
  margin-top: 8px;
}

.btn-cancel {
  padding: 10px 20px;
  background: transparent;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--text-secondary);
  font-family: var(--font-mono);
  font-size: 12px;
  cursor: pointer;
  transition: border-color 0.2s, color 0.2s;
}

.btn-cancel:hover { border-color: var(--text-secondary); color: var(--text-primary); }

/* ---- Toast ---- */
.toast {
  position: fixed;
  bottom: 28px;
  right: 28px;
  background: var(--bg-raised);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 12px 18px;
  font-family: var(--font-mono);
  font-size: 12px;
  color: var(--text-primary);
  box-shadow: var(--shadow);
  z-index: 300;
  transform: translateY(20px);
  opacity: 0;
  transition: transform 0.3s ease, opacity 0.3s ease;
  pointer-events: none;
  max-width: 320px;
}

.toast.show { transform: translateY(0); opacity: 1; }
.toast.success { border-color: rgba(39, 174, 96, 0.4); color: var(--green); }
.toast.error { border-color: rgba(192, 57, 43, 0.4); color: var(--red); }

/* ---- Animations ---- */
@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

@keyframes slideUp {
  from { opacity: 0; transform: translateY(12px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes scaleIn {
  from { opacity: 0; transform: scale(0.95); }
  to { opacity: 1; transform: scale(1); }
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* ---- Responsive ---- */
@media (max-width: 768px) {
  .app-layout { flex-direction: column; }
  .sidebar {
    width: 100%;
    min-width: auto;
    max-height: 220px;
    border-right: none;
    border-bottom: 1px solid var(--border);
  }
  .project-view { padding: 24px 20px; }
  .project-title { font-size: 26px; }
}

/* =========================================================
   AudioScript — Dark Editorial Theme
   Fonts: Playfair Display, Lora, DM Mono
   ========================================================= */

:root {
  --bg-base: #0d0d0f;
  --bg-surface: #131316;
  --bg-raised: #1a1a1f;
  --bg-hover: #202028;
  --bg-active: #252530;

  --border: rgba(255, 255, 255, 0.07);
  --border-focus: rgba(212, 175, 95, 0.5);

  --gold: #d4af5f;
  --gold-dim: rgba(212, 175, 95, 0.12);
  --gold-bright: #e8c87a;

  --text-primary: #f0ece0;
  --text-secondary: #9a9585;
  --text-muted: #5a5650;

  --red: #c0392b;
  --red-dim: rgba(192, 57, 43, 0.15);
  --green: #2ecc71;

  --font-display: 'Playfair Display', Georgia, serif;
  --font-body: 'Lora', Georgia, serif;
  --font-mono: 'DM Mono', 'Courier New', monospace;

  --radius: 4px;
  --radius-lg: 8px;
  --sidebar-width: 280px;
  --header-height: 56px;

  --shadow: 0 4px 24px rgba(0, 0, 0, 0.4);
  --shadow-lg: 0 8px 48px rgba(0, 0, 0, 0.6);
}

/* ---- Reset ---- */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { height: 100%; scroll-behavior: smooth; }
body {
  height: 100%;
  background: var(--bg-base);
  color: var(--text-primary);
  font-family: var(--font-body);
  font-size: 15px;
  line-height: 1.65;
  overflow: hidden;
}

/* ---- Background ---- */
.bg-texture {
  position: fixed;
  inset: 0;
  background-image:
    radial-gradient(ellipse at 20% 20%, rgba(212, 175, 95, 0.04) 0%, transparent 50%),
    radial-gradient(ellipse at 80% 80%, rgba(100, 80, 160, 0.04) 0%, transparent 50%);
  pointer-events: none;
  z-index: 0;
}

/* ---- Header ---- */
.site-header {
  position: fixed;
  top: 0; left: 0; right: 0;
  height: var(--header-height);
  background: rgba(13, 13, 15, 0.95);
  backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--border);
  z-index: 100;
}
.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 100%;
  padding: 0 24px;
}
.logo { display: flex; align-items: center; gap: 10px; }
.logo-icon { color: var(--gold); font-size: 18px; line-height: 1; }
.logo-text {
  font-family: var(--font-display);
  font-size: 17px;
  font-weight: 700;
  letter-spacing: 0.04em;
