  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 18px;
  line-height: 1;
  padding: 0 4px;
  transition: color 0.15s;
}
.file-remove:hover { color: var(--red); }

.form-actions { display: flex; justify-content: flex-end; }
.btn-submit {
  padding: 10px 24px;
  background: var(--gold);
  color: #0d0d0f;
  border: none;
  border-radius: var(--radius);
  font-family: var(--font-mono);
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.06em;
  cursor: pointer;
  transition: background 0.2s, transform 0.1s;
}
.btn-submit:hover { background: var(--gold-bright); transform: translateY(-1px); }
.btn-submit:active { transform: translateY(0); }
.btn-submit:disabled { opacity: 0.5; cursor: not-allowed; transform: none; }

/* ---- Entries Section ---- */
.entries-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 20px;
}
.entries-title {
  font-family: var(--font-mono);
  font-size: 10px;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--text-muted);
}
.entries-count { font-family: var(--font-mono); font-size: 11px; color: var(--text-muted); }
.entries-list { display: flex; flex-direction: column; gap: 16px; padding-bottom: 60px; }

/* Entry card */
.entry-card {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 20px 24px;
  transition: border-color 0.2s;
  animation: slideUp 0.3s ease;
}
.entry-card:hover { border-color: rgba(212, 175, 95, 0.2); }
.entry-card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 14px;
}
.entry-date { font-family: var(--font-mono); font-size: 10px; color: var(--text-muted); letter-spacing: 0.06em; }
.entry-delete-btn {
  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  opacity: 0;
  transition: opacity 0.2s, color 0.2s;
  padding: 2px 6px;
  font-size: 12px;
  font-family: var(--font-mono);
}
.entry-card:hover .entry-delete-btn { opacity: 1; }
.entry-delete-btn:hover { color: var(--red); }
.entry-text {
  font-size: 14px;
  color: var(--text-primary);
  line-height: 1.75;
  white-space: pre-wrap;
  word-break: break-word;
}
.entry-audio-wrapper {
  margin-top: 16px;
  padding-top: 16px;
  border-top: 1px solid var(--border);
}
.entry-audio-label {
  font-family: var(--font-mono);
  font-size: 10px;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--gold);
  margin-bottom: 10px;
  display: flex;
  align-items: center;
  gap: 6px;
}
.entry-audio-label::before { content: '♪'; font-size: 12px; }
.entry-filename { font-family: var(--font-mono); font-size: 11px; color: var(--text-muted); margin-bottom: 8px; }
audio { width: 100%; height: 36px; border-radius: var(--radius); }

.empty-entries { text-align: center; padding: 48px 20px; }
.empty-entries-icon { font-size: 32px; color: var(--text-muted); opacity: 0.3; display: block; margin-bottom: 12px; }
.empty-entries p { font-size: 13px; color: var(--text-muted); font-style: italic; }

/* Spinner */
.spinner {
  width: 28px;
  height: 28px;
  border: 2px solid var(--border);
  border-top-color: var(--gold);
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
  margin: 40px auto;
}
.entries-loading { display: flex; justify-content: center; }

/* ---- Modals ---- */
.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.75);
  backdrop-filter: blur(4px);
  z-index: 200;
  display: flex;
  align-items: center;
  justify-content: center;
  animation: fadeIn 0.2s ease;
}
.modal {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 32px;
  width: 480px;
  max-width: 90vw;
  box-shadow: var(--shadow-lg);
  animation: scaleIn 0.2s ease;
}
.modal-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 24px;
}
.modal-title { font-family: var(--font-display); font-size: 22px; font-weight: 700; color: var(--text-primary); }
.modal-close {
  background: none;
  border: none;
  color: var(--text-muted);
  font-size: 22px;
  cursor: pointer;
  line-height: 1;
  transition: color 0.15s;
  padding: 2px;
}
.modal-close:hover { color: var(--text-primary); }
.modal-form .form-field { margin-bottom: 20px; }
.modal-actions { display: flex; justify-content: flex-end; gap: 10px; margin-top: 8px; }
.btn-cancel {
  padding: 10px 20px;
  background: transparent;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--text-secondary);
  font-family: var(--font-mono);
  font-size: 12px;
  cursor: pointer;
  transition: border-color 0.2s, color 0.2s;
}
.btn-cancel:hover { border-color: var(--text-secondary); color: var(--text-primary); }

/* ---- Toast ---- */
.toast {
  position: fixed;
  bottom: 28px;
  right: 28px;
  background: var(--bg-raised);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 12px 18px;
  font-family: var(--font-mono);
  font-size: 12px;
  color: var(--text-primary);
  box-shadow: var(--shadow);
  z-index: 300;
  transform: translateY(20px);
  opacity: 0;
  transition: transform 0.3s ease, opacity 0.3s ease;
  pointer-events: none;
  max-width: 320px;
}
.toast.show { transform: translateY(0); opacity: 1; }
.toast.success { border-color: rgba(46, 204, 113, 0.4); color: var(--green); }
.toast.error { border-color: rgba(192, 57, 43, 0.4); color: var(--red); }

/* ---- Animations ---- */
@keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
@keyframes slideUp { from { opacity: 0; transform: translateY(12px); } to { opacity: 1; transform: translateY(0); } }
@keyframes scaleIn { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
@keyframes spin { to { transform: rotate(360deg); } }

/* ---- Responsive ---- */
@media (max-width: 768px) {
  .app-layout { flex-direction: column; overflow: auto; }
  body { overflow: auto; }
  .sidebar { width: 100%; min-width: auto; max-height: 220px; border-right: none; border-bottom: 1px solid var(--border); }
  .project-view { padding: 24px 20px; }
  .project-title { font-size: 26px; }
}
