  viewProjectDesc.textContent = project.description || '';
  viewProjectDesc.style.display = project.description ? 'block' : 'none';

  entryForm.reset();
  clearAudioFile();
  await loadEntries(id);
}

async function loadEntries(projectId) {
  entriesLoading.style.display = 'flex';
  entriesList.innerHTML = '';

  try {
    const data = await api.get(`/api/projects/${projectId}`);
    const entries = data.entries || [];
    entriesCount.textContent = `${entries.length} mục`;
    renderEntries(entries);
  } catch (err) {
    entriesList.innerHTML = `<p style="color:var(--red);font-family:var(--font-mono);font-size:12px">Lỗi tải nội dung</p>`;
  } finally {
    entriesLoading.style.display = 'none';
  }
}

function renderEntries(entries) {
  if (entries.length === 0) {
    entriesList.innerHTML = `
      <div class="empty-entries">
        <span class="empty-entries-icon">◎</span>
        <p>Chưa có nội dung nào. Hãy thêm văn bản và audio bên trên.</p>
      </div>`;
    return;
  }

  entriesList.innerHTML = entries.map(e => `
    <div class="entry-card" data-id="${e.id}">
      <div class="entry-card-header">
        <span class="entry-date">${formatDateFull(e.created_at)}</span>
        <button class="entry-delete-btn" onclick="deleteEntry(${e.id})">Xóa</button>
      </div>
      <p class="entry-text">${escapeHtml(e.text_content)}</p>
      ${e.audio_url ? `
        <div class="entry-audio-wrapper">
          <div class="entry-audio-label">Audio</div>
          ${e.audio_filename ? `<div class="entry-filename">${escapeHtml(e.audio_filename)}</div>` : ''}
          <audio controls src="${e.audio_url}"></audio>
        </div>` : ''}
    </div>
  `).join('');
}

// ---- Create Project ----
function openCreateModal() {
  createProjectForm.reset();
  document.getElementById('name-error').textContent = '';
  modalCreateProject.style.display = 'flex';
}

function closeCreateModal() {
  modalCreateProject.style.display = 'none';
}

async function handleCreateProject(e) {
  e.preventDefault();
  const name = document.getElementById('project-name').value.trim();
  const description = document.getElementById('project-description').value.trim();

  if (!name) {
    document.getElementById('name-error').textContent = 'Vui lòng nhập tên dự án';
    return;
  }

  try {
    const project = await api.post('/api/projects', { name, description: description || null });
    projects.unshift({ ...project, entry_count: 0 });
    renderSidebar();
    closeCreateModal();
    selectProject(project.id);
    showToast('Đã tạo dự án thành công', 'success');
  } catch (err) {
    showToast(`Lỗi: ${err.message}`, 'error');
  }
}

// ---- Edit Project ----
function openEditModal(project) {
  document.getElementById('edit-project-id').value = project.id;
  document.getElementById('edit-project-name').value = project.name;
  document.getElementById('edit-project-desc').value = project.description || '';
  modalEditProject.style.display = 'flex';
}

function closeEditModal() {
  modalEditProject.style.display = 'none';
}

async function handleEditProject(e) {
  e.preventDefault();
  const id = parseInt(document.getElementById('edit-project-id').value);
  const name = document.getElementById('edit-project-name').value.trim();
  const description = document.getElementById('edit-project-desc').value.trim();

  if (!name) return;

  try {
    const updated = await api.put(`/api/projects/${id}`, { name, description: description || null });
    const idx = projects.findIndex(p => p.id === id);
    if (idx !== -1) projects[idx] = { ...projects[idx], ...updated };
    renderSidebar();
    viewProjectTitle.textContent = updated.name;
    viewProjectDesc.textContent = updated.description || '';
    viewProjectDesc.style.display = updated.description ? 'block' : 'none';
    closeEditModal();
    showToast('Đã cập nhật dự án', 'success');
  } catch (err) {
    showToast(`Lỗi: ${err.message}`, 'error');
  }
}

// ---- Delete Project ----
async function handleDeleteProject() {
  if (!currentProjectId) return;
  const project = projects.find(p => p.id === currentProjectId);
  if (!confirm(`Bạn có chắc muốn xóa dự án "${project?.name}"? Tất cả nội dung sẽ bị xóa.`)) return;

  try {
    await api.delete(`/api/projects/${currentProjectId}`);
    projects = projects.filter(p => p.id !== currentProjectId);
    currentProjectId = null;
    renderSidebar();
    welcomeScreen.style.display = 'flex';
    projectView.style.display = 'none';
    showToast('Đã xóa dự án', 'success');
  } catch (err) {
    showToast(`Lỗi: ${err.message}`, 'error');
  }
}

// ---- Add Entry ----
async function handleAddEntry(e) {
  e.preventDefault();
  const textContent = entryTextarea.value.trim();
  document.getElementById('text-error').textContent = '';

  if (!textContent) {
    document.getElementById('text-error').textContent = 'Vui lòng nhập nội dung văn bản';
    return;
  }

  const submitBtn = btnAddEntry;
  const btnText = submitBtn.querySelector('.btn-text');
  const btnLoading = submitBtn.querySelector('.btn-loading');
  submitBtn.disabled = true;
  btnText.style.display = 'none';
  btnLoading.style.display = 'inline';

  try {
    const formData = new FormData();
    formData.append('text_content', textContent);
    const audioFile = audioFileInput.files[0];
    if (audioFile) formData.append('audio_file', audioFile);

    const entry = await api.uploadForm(`/api/projects/${currentProjectId}/entries`, formData);

    // Refresh entries
    entryForm.reset();
    clearAudioFile();
    await loadEntries(currentProjectId);

    // Update entry count in sidebar
    const proj = projects.find(p => p.id === currentProjectId);
    if (proj) { proj.entry_count++; renderSidebar(); }

    showToast('Đã lưu nội dung', 'success');
  } catch (err) {
    showToast(`Lỗi: ${err.message}`, 'error');
  } finally {
    submitBtn.disabled = false;
    btnText.style.display = 'inline';
    btnLoading.style.display = 'none';
  }
}

// ---- Delete Entry ----
async function deleteEntry(entryId) {
  if (!confirm('Xóa nội dung này?')) return;
  try {
    await api.delete(`/api/projects/${currentProjectId}/entries/${entryId}`);
    await loadEntries(currentProjectId);
    const proj = projects.find(p => p.id === currentProjectId);
    if (proj && proj.entry_count > 0) { proj.entry_count--; renderSidebar(); }
    showToast('Đã xóa nội dung', 'success');
  } catch (err) {
    showToast(`Lỗi: ${err.message}`, 'error');
  }
}

// ---- Audio file helpers ----
function setAudioFile(file) {
  const dt = new DataTransfer();
  dt.items.add(file);
  audioFileInput.files = dt.files;
  selectedFilename.textContent = file.name;
  dropZoneContent.style.display = 'none';
  fileSelected.style.display = 'flex';
}

function clearAudioFile() {
  audioFileInput.value = '';
  dropZoneContent.style.display = 'block';
  fileSelected.style.display = 'none';
  selectedFilename.textContent = '';
}

// ---- Toast ----
let toastTimer = null;
function showToast(message, type = '') {
  toast.textContent = message;
  toast.className = `toast show ${type}`;
  if (toastTimer) clearTimeout(toastTimer);
  toastTimer = setTimeout(() => { toast.className = 'toast'; }, 3000);
}

// ---- Helpers ----
function escapeHtml(text) {
  const div = document.createElement('div');
  div.textContent = String(text ?? '');
  return div.innerHTML;
}

function formatDate(dateString) {
  return new Date(dateString).toLocaleDateString('vi-VN', { year: 'numeric', month: 'short', day: 'numeric' });
}

function formatDateFull(dateString) {
  return new Date(dateString).toLocaleString('vi-VN', {
    year: 'numeric', month: '2-digit', day: '2-digit',
    hour: '2-digit', minute: '2-digit'
  });
}

